import os
from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core

class PrismGetSequenceByProjectNode(BaseNode):
    name = "Prism: Get Sequence by Project"
    category = "DCCs"

    def __init__(self):
        super().__init__(use_exec=False)
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_input("project", "dict")
        self.add_input("name", "string", widget_type="text", default="")
        self.add_output("sequence", "dict")
        self.add_output("found", "bool")

    def _project_path(self, project):
        path = project.get('project_path', '')
        if not path:
            cfg = project.get('configPath', '')
            if cfg:
                path = os.path.dirname(os.path.dirname(cfg))
        return path

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        project = inputs.get('project') or {}
        name = (inputs.get('name') or '').strip()
        empty = {'sequence': {}, 'found': False}
        if core is None:
            self.log_error('No PrismCore found.')
            return empty
        if not project:
            self.log_error('No project provided.')
            return empty
        if not name:
            self.log_error('No sequence name provided.')
            return empty
        prj_path = self._project_path(project)
        if not prj_path:
            self.log_error('Cannot determine project path from project dict.')
            return empty
        try:
            core.changeProject(prj_path)
        except Exception as e:
            self.log_error(f'changeProject failed: {e}')
            return empty
        try:
            shots = list(core.entities.getShots() or [])
            sequences = list(dict.fromkeys(
                str(s.get('sequence', '')) for s in shots
                if isinstance(s, dict) and s.get('sequence')
            ))
        except Exception as e:
            self.log_error(f'getShots failed: {e}')
            return empty
        name_lower = name.lower()
        for seq in sequences:
            if str(seq).lower() == name_lower:
                seq_dict = {
                    'name': str(seq),
                    'project_path': prj_path,
                    'project_name': project.get('name', ''),
                }
                self.log_info(f"Found sequence '{seq}' in '{project.get('name', '')}'")
                return {'sequence': seq_dict, 'found': True}
        self.log_error(f"Sequence '{name}' not found in {len(sequences)} sequence(s).")
        return empty

def register_node():
    return PrismGetSequenceByProjectNode
